using System.Globalization;

namespace DriveScan.Services;

public enum Language { EN, DE, FR, ES, JA, ZH, RU }

public static class L10n
{
    private static Language _current;
    public static Language Current
    {
        get => _current;
        set { _current = value; LanguageChanged?.Invoke(); }
    }

    public static event Action? LanguageChanged;

    static L10n() { _current = DetectSystemLanguage(); }

    public static Language DetectSystemLanguage()
    {
        var c = CultureInfo.CurrentUICulture.TwoLetterISOLanguageName.ToLowerInvariant();
        return c switch { "de" => Language.DE, "fr" => Language.FR, "es" => Language.ES, "ja" => Language.JA, "zh" => Language.ZH, "ru" => Language.RU, _ => Language.EN };
    }

    public static string Get(string key)
    {
        if (S.TryGetValue(key, out var t) && t.TryGetValue(_current, out var v)) return v;
        if (S.TryGetValue(key, out t) && t.TryGetValue(Language.EN, out v)) return v;
        return key;
    }

    public static string Format(string key, params object[] args) => string.Format(Get(key), args);

